	col += texture2D(u_image, uv + vec2(OFFSET, OFFSET)) * BLUR_WEIGHT; // top-right

	col += texture2D(u_image, uv + vec2(-OFFSET, 0.0)) * BLUR_WEIGHT; // centre-left
	col += texture2D(u_image, uv + vec2(0.0, 0.0)) * BLUR_WEIGHT; // centre-centre
	col += texture2D(u_image, uv + vec2(OFFSET, 0.0)) * BLUR_WEIGHT; // centre-right

	col += texture2D(u_image, uv + vec2(-OFFSET, -OFFSET)) * BLUR_WEIGHT; // bottom-left
	col += texture2D(u_image, uv + vec2(0.0, -OFFSET)) * BLUR_WEIGHT; // bottom-centre
	col += texture2D(u_image, uv + vec2(OFFSET, -OFFSET)) * BLUR_WEIGHT; // bottom-right

